const dateFmt=(t,e="yyyy-MM-dd HH:mm:ss")=>{let a=new Date;if(t&&(a=new Date(t)),isNaN(a.getTime()))throw new Error("Invalid date");const r=a.getFullYear(),n=a.getMonth(),p=a.getDate(),l=a.getHours(),d=a.getMinutes(),g=a.getSeconds(),u=a.getDay(),S=l>=12?"下午":"上午",v=l%12||12,i=[{pattern:"yyyy",value:String(r).padStart(4,"0")},{pattern:"yy",value:String(r).slice(-2)},{pattern:"MMMM",value:["一月","二月","三月","四月","五月","六月","七月","八月","九月","十月","十一月","十二月"][n]},{pattern:"MMM",value:["1月","2月","3月","4月","5月","6月","7月","8月","9月","10月","11月","12月"][n]},{pattern:"MM",value:String(n+1).padStart(2,"0")},{pattern:"M",value:String(n+1)},{pattern:"dddd",value:["星期日","星期一","星期二","星期三","星期四","星期五","星期六"][u]},{pattern:"ddd",value:["周日","周一","周二","周三","周四","周五","周六"][u]},{pattern:"dd",value:String(p).padStart(2,"0")},{pattern:"d",value:String(p)},{pattern:"HH",value:String(l).padStart(2,"0")},{pattern:"H",value:String(l)},{pattern:"hh",value:String(v).padStart(2,"0")},{pattern:"h",value:String(v)},{pattern:"mm",value:String(d).padStart(2,"0")},{pattern:"m",value:String(d)},{pattern:"ss",value:String(g).padStart(2,"0")},{pattern:"s",value:String(g)},{pattern:"tt",value:S}];let s=e;for(const t of i){const e=new RegExp(t.pattern.replace(/[.*+?^${}()|[\]\\]/g,"\\$&"),"g");s=s.replace(e,t.value)}return s};export default{dateFmt:dateFmt};